sql:
SELECT COUNT(call_type_id)
FROM call_types
WHERE is_emergency = 1;

external_knowledge:
- 'Medical Incident' refers to incidents that require medical attention; 
- 'Medium' priority indicates that the incident is not life-threatening but requires attention; 
- 'ALS' stands for Advanced Life Support, which refers to emergency medical services that provide advanced care; 
- 'Call type group 1' is a specific category of calls that may require immediate attention.

sql:
SELECT AVG(delay) AS average_delay
FROM calls
WHERE num_alarms = '1' AND station_area = 42 AND call_final_disposition = 'Other';

SELECT district_name
FROM fire_districts
WHERE district_risk_level = 'High';
